            for (int j = 0; j <= target; j++) {
                if (i > 0) dp[i][j] = dp[i-1][j];
                if (j >= nums[i-1]) dp[i][j] = max(dp[i][j], dp[i-1][j-nums[i-1]] + nums[i-1]);
            }
        }
        return dp[n][target];
