class Solution {
public:
    int maxScore(int* nums, int n, int target) {
        if (n == 0 || target == 0) return 0;
        int dp[n+1][target+1] = {{0}};
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= target; j++) {
                if (j >= nums[i-1]) dp[i][j] = max(dp[i-1][j], dp[i-1][j-nums[i-1]] + nums[i-1]);
                else dp[i][j] = dp[i-1][j];
            }
        }
        return dp[n][target];
    }
};
